   320→### 2. Create PowerShell Status Line Script
   321→**File**: `.claude/statusline-command.ps1` (NEW FILE)
   322→
   323→**Convert from bash to PowerShell:**
   324→
   325→```powershell
   326→# PAI v2.5 Status Line - PowerShell Version
   327→# Equivalent to statusline-command.sh for Windows
   328→
   329→param(
   330→    [string]$Mode = "normal",
   331→    [switch]$Debug
   332→)
   333→
   334→$ErrorActionPreference = "SilentlyContinue"
   335→
   336→# Color schemes
   337→$colors = @{
   338→    reset = "`e[0m"
   339→    bold = "`e[1m"
   340→    dim = "`e[2m"
   341→
   342→    # Foreground colors
   343→    black = "`e[30m"
   344→    red = "`e[31m"
   345→    green = "`e[32m"
   346→    yellow = "`e[33m"
   347→    blue = "`e[34m"
   348→    magenta = "`e[35m"
   349→    cyan = "`e[36m"
   350→    white = "`e[37m"
   351→
   352→    # Background colors
   353→    bg_black = "`e[40m"
   354→    bg_red = "`e[41m"
   355→    bg_green = "`e[42m"
   356→    bg_yellow = "`e[43m"
   357→    bg_blue = "`e[44m"
   358→    bg_magenta = "`e[45m"
   359→    bg_cyan = "`e[46m"
   360→    bg_white = "`e[47m"
   361→}
   362→
   363→function Get-GitStatus {
   364→    $gitDir = git rev-parse --git-dir 2>$null
   365→    if (-not $gitDir) {
   366→        return ""
   367→    }
   368→
   369→    $branch = git rev-parse --abbrev-ref HEAD 2>$null
   370→    if (-not $branch) {
   371→        return ""
   372→    }
   373→
   374→    $status = git status --porcelain 2>$null
   375→    $hasChanges = $status -and $status.Length -gt 0
   376→
   377→    $symbol = if ($hasChanges) { "*" } else { "" }
   378→    return "$branch$symbol"
   379→}
   380→
   381→function Get-CurrentDirectory {
   382→    $path = (Get-Location).Path
   383→    $home = $env:USERPROFILE
   384→
   385→    if ($path.StartsWith($home)) {
   386→        $path = $path.Replace($home, "~")
   387→    }
   388→
   389→    # Limit length
   390→    if ($path.Length -gt 40) {
   391→        $parts = $path.Split('\')
   392→        $path = "$($parts[0])\...\$($parts[-1])"
   393→    }
   394→
   395→    return $path
   396→}
   397→
   398→function Get-PaiInfo {
   399→    $paiHome = "$env:USERPROFILE\.claude"
   400→    $settingsFile = "$paiHome\settings.json"
   401→
   402→    if (Test-Path $settingsFile) {
   403→        try {
   404→            $settings = Get-Content $settingsFile | ConvertFrom-Json
   405→            return $settings.daidentity.name
   406→        } catch {
   407→            return "PAI"
   408→        }
   409→    }
   410→
   411→    return "PAI"
   412→}
   413→
   414→function Get-DateTime {
   415→    return Get-Date -Format "HH:mm:ss"
   416→}
   417→
   418→function Get-WindowSize {
   419→    $ui = $Host.UI.RawUI
   420→    return $ui.WindowSize.Width
   421→}
   422→
   423→function Show-StatusLine {
   424→    $width = Get-WindowSize
   425→    $leftPad = 1
   426→    $rightPad = 1
   427→
   428→    # Build left side
   429→    $paiInfo = Get-PaiInfo
   430→    $gitStatus = Get-GitStatus
   431→    $currentDir = Get-CurrentDirectory
   432→
   433→    $leftParts = @($paiInfo, $gitStatus, $currentDir)
   434→    $leftText = $leftParts -join " | "
   435→    $leftText = $leftText.PadRight($width / 2)
   436→
   437→    # Build right side
   438→    $dateTime = Get-DateTime
   439→    $rightText = $dateTime.PadLeft($width / 2)
   440→
   441→    # Combine
   442→    $statusLine = "$leftText$rightText"
   443→
   444→    # Apply colors
   445→    $coloredLine = "$($colors.bold)$($colors.cyan)$statusLine$($colors.reset)"
   446→
   447→    # Write status line
   448→    Write-Host "`r$coloredLine" -NoNewline
   449→}
   450→
   451→# Main loop
   452→try {
   453→    while ($true) {
   454→        Show-StatusLine
   455→        Start-Sleep -Milliseconds 100
   456→    }
   457→} catch {
   458→    Write-Host "Status line error: $_" -ForegroundColor Red
   459→}
   460→```
