   462→### 3. Adapt VoiceServer for Windows
   463→**Files**:
   464→- `.claude/VoiceServer/server.py`
   465→- `.claude/VoiceServer/start.sh` → Create `start.ps1`
   466→- `.claude/VoiceServer/stop.sh` → Create `stop.ps1`
   467→
   468→**Windows Startup Script (start.ps1):**
   469→
   470→```powershell
   471→# VoiceServer Windows Startup Script
   472→
   473→$VoiceDir = "$env:USERPROFILE\.claude\VoiceServer"
   474→$PidFile = "$VoiceDir\voice.pid"
   475→$LogFile = "$VoiceDir\voice.log"
   476→
   477→# Check if already running
   478→if (Test-Path $PidFile) {
   479→    $oldPid = Get-Content $PidFile
   480→    $process = Get-Process -Id $oldPid -ErrorAction SilentlyContinue
   481→
   482→    if ($process) {
   483→        Write-Host "VoiceServer is already running (PID: $oldPid)" -ForegroundColor Yellow
   484→        exit 1
   485→    } else {
   486→        Remove-Item $PidFile
   487→    }
   488→}
   489→
   490→# Start the server
   491→Write-Host "Starting VoiceServer..." -ForegroundColor Green
   492→
   493→# Use uvicorn (Python HTTP server)
