   495→$process = Start-Process -FilePath "uvicorn" -ArgumentList @(
   496→    "server:app",
   497→    "--host", "127.0.0.1",
   498→    "--port", "8888",
   499→    "--log-level", "info"
   500→) -PassThru -RedirectStandardOutput $LogFile -RedirectStandardError $LogFile -NoNewWindow
   501→
   502→# Save PID
