#!/usr/bin/env bun
/**
 * PAI Installation Wizard - Cross-Platform v2.5
 *
 * Interactive setup that walks you through personalizing your PAI:
 * - Sets your name and timezone
 * - Names your AI assistant
 * - Configures voice settings
 * - Fixes permissions and starts services
 *
 * Platform Support:
 * - Windows: PowerShell + Windows commands
 * - macOS: zsh + Unix commands
 * - Linux: bash/zsh + Unix commands
 *
 * Usage:
 *   bun run INSTALL.ts    # Run the interactive wizard
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, sep } from 'path';
import { homedir, userInfo, platform } from 'os';
import { execSync, spawn } from 'child_process';
import * as readline from 'readline';

// ============================================================================
// PLATFORM DETECTION
// ============================================================================

const PLATFORM = process.platform;
const IS_WINDOWS = PLATFORM === 'win32';
const IS_MAC = PLATFORM === 'darwin';
const IS_LINUX = PLATFORM === 'linux';

// Platform-specific paths
const HOME = IS_WINDOWS
  ? process.env.USERPROFILE || homedir()
  : process.env.HOME || homedir();

const CLAUDE_DIR = join(HOME, '.claude');
const VOICE_SERVER_DIR = join(CLAUDE_DIR, 'VoiceServer');
const VOICE_SERVER_PORT = 8888;

// ANSI colors (work on all platforms with modern terminals)
const c = {
  reset: '\x1b[0m',
  bold: '\x1b[1m',
  blue: '\x1b[38;2;59;130;246m',
  green: '\x1b[38;2;34;197;94m',
  yellow: '\x1b[38;2;234;179;8m',
  red: '\x1b[38;2;239;68;68m',
  cyan: '\x1b[38;2;6;182;212m',
  gray: '\x1b[38;2;100;116;139m',
};

// Default voice IDs - ElevenLabs pre-made voices
const DEFAULT_VOICES = {
  male: 'pNInz6obpgDQGcFmaJgB',      // Adam (male)
  female: '21m00Tcm4TlvDq8ikWAM',    // Rachel (female)
  neutral: 'ErXwobaYiN019PkySvjV',   // Antoni (versatile male)
};

interface InstallConfig {
  PRINCIPAL_NAME: string;
  TIMEZONE?: string;
  AI_NAME?: string;
  CATCHPHRASE?: string;
  VOICE_TYPE?: 'male' | 'female' | 'neutral';
  ELEVENLABS_KEY?: string;
  CUSTOM_VOICE_ID?: string;
  PROJECTS_DIR?: string;
}

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

function print(msg: string) { console.log(msg); }
function printSuccess(msg: string) { print(`  ${c.green}✓${c.reset} ${msg}`); }
function printWarning(msg: string) { print(`  ${c.yellow}!${c.reset} ${msg}`); }
function printError(msg: string) { print(`  ${c.red}✗${c.reset} ${msg}`); }
function printInfo(msg: string) { print(`  ${c.gray}→${c.reset} ${msg}`); }

function createReadline(): readline.Interface {
  return readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });
}

async function prompt(question: string, defaultValue?: string): Promise<string> {
  const displayDefault = defaultValue ? ` ${c.gray}[${defaultValue}]${c.reset}` : '';
  const rl = createReadline();

  return new Promise((resolve) => {
    rl.question(`  ${question}${displayDefault}: `, (answer) => {
      rl.close();
      resolve(answer.trim() || defaultValue || '');
    });
  });
}

async function promptChoice(question: string, choices: string[], defaultIdx = 0): Promise<number> {
  print(`  ${question}`);
  choices.forEach((choice, i) => {
    const marker = i === defaultIdx ? `${c.cyan}→${c.reset}` : ' ';
    print(`    ${marker} ${i + 1}. ${choice}`);
  });

  const rl = createReadline();
  return new Promise((resolve) => {
    rl.question(`  ${c.gray}Enter 1-${choices.length} [${defaultIdx + 1}]:${c.reset} `, (answer) => {
      rl.close();
      const num = parseInt(answer.trim()) || (defaultIdx + 1);
      resolve(Math.max(0, Math.min(choices.length - 1, num - 1)));
    });
  });
}

// ============================================================================
// CROSS-PLATFORM PERMISSIONS
// ============================================================================

function fixPermissions(targetDir: string): void {
  print('');
  print(`${c.bold}Fixing permissions${c.reset}`);
  print(`${c.gray}─────────────────────────────────────────────────${c.reset}`);

  try {
    if (IS_WINDOWS) {
      // Windows: Use icacls if needed, or skip (default permissions usually OK)
      printInfo('Platform: Windows (using default permissions)');

      try {
        const username = userInfo().username;
        execSync(`icacls "${targetDir}" /grant "${username}:(OI)(CI)F" /T`, {
          stdio: 'pipe',
          shell: true
        });
        printSuccess('Set Windows permissions');
      } catch (err) {
        printWarning('icacls failed (may need admin privileges)');
        printInfo('Default permissions should work for most operations');
      }
    } else {
      // Unix: chmod and chown
      const info = userInfo();
      printInfo(`Platform: ${IS_MAC ? 'macOS' : 'Linux'}`);

      // Step 1: chmod first - make files accessible
      execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
      printSuccess('Step 1: chmod -R 755 (make accessible)');

      // Step 2: chown - change ownership to current user
      execSync(`chown -R ${info.uid}:${info.gid} "${targetDir}"`, { stdio: 'pipe' });
      printSuccess(`Step 2: chown -R to ${info.username}`);

      // Step 3: chmod again - set final permissions
      execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
      printSuccess('Step 3: chmod -R 755 (final permissions)');
    }

    // Make scripts executable (cross-platform)
    printInfo('Setting executable permissions...');
    const execFiles = findExecutableFiles(targetDir);
    for (const file of execFiles) {
      makeExecutable(file);
    }
    printSuccess(`Set executable permissions on ${execFiles.length} files`);

  } catch (err: any) {
    printError(`Permission fix failed: ${err.message}`);
    if (!IS_WINDOWS) {
      print(`${c.yellow}Run: sudo chown -R $(whoami) ${targetDir}${c.reset}`);
    }
  }
}

// Cross-platform file search (replaces Unix find)
function findExecutableFiles(dir: string, patterns: string[] = ['*.ts', '*.sh', '*.py']): string[] {
  const results: string[] = [];

  function walk(currentPath: string) {
    try {
      const files = readdirSync(currentPath);
      for (const file of files) {
        const fullPath = join(currentPath, file);
        try {
          const stat = require('fs').statSync(fullPath);

          if (stat.isDirectory()) {
            walk(fullPath);
          } else {
            // Check if file matches any pattern
            for (const pattern of patterns) {
              const regex = new RegExp(`^${pattern.replace('*', '.*')}$`);
              if (regex.test(file)) {
                results.push(fullPath);
                break;
              }
            }
          }
        } catch (e) {
          // Skip files we can't read
        }
      }
    } catch (e) {
      // Skip directories we can't read
    }
  }

  walk(dir);
  return results;
}

// Cross-platform executable permission
function makeExecutable(filePath: string): void {
  if (IS_WINDOWS) {
    // Windows: Files are executable by extension (.exe, .bat, .ps1)
    // For other files, no action needed (Git handles permissions)
    return;
  } else {
    // Unix: chmod +x
    try {
      execSync(`chmod +x "${filePath}"`, { stdio: 'pipe' });
    } catch (e) {
      // Ignore errors
    }
  }
}

// ============================================================================
// CROSS-PLATFORM VOICE SERVER MANAGEMENT
// ============================================================================

function findRunningVoiceServers(): number[] {
  try {
    if (IS_WINDOWS) {
      // Windows: Use netstat to find process using port
      const result = execSync(`netstat -ano | findstr :${VOICE_SERVER_PORT}`, {
        encoding: 'utf-8',
        stdio: ['pipe', 'pipe', 'pipe']
      });
      const pids: number[] = [];
      const lines = result.trim().split('\n');
      for (const line of lines) {
        const parts = line.trim().split(/\s+/);
        const pid = parseInt(parts[parts.length - 1]);
        if (!isNaN(pid)) {
          pids.push(pid);
        }
      }
      return [...new Set(pids)]; // Unique PIDs
    } else {
      // Unix: Use lsof
      const result = execSync(`lsof -ti:${VOICE_SERVER_PORT}`, {
        encoding: 'utf-8',
        stdio: ['pipe', 'pipe', 'pipe']
      });
      return result.trim().split('\n').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
    }
  } catch (e) {
    return [];
  }
}

function killVoiceServers(): void {
  const pids = findRunningVoiceServers();
  if (pids.length > 0) {
    printInfo(`Killing ${pids.length} existing voice server(s)`);
    for (const pid of pids) {
      try {
        if (IS_WINDOWS) {
          execSync(`taskkill /F /PID ${pid}`, { stdio: 'pipe' });
        } else {
          execSync(`kill -9 ${pid}`, { stdio: 'pipe' });
        }
        printSuccess(`Killed process ${pid}`);
      } catch (e) { /* ignore */ }
    }
  }
}

async function startVoiceServer(): Promise<boolean> {
  if (IS_WINDOWS) {
    const startScript = join(VOICE_SERVER_DIR, 'start.ps1');
    if (!existsSync(startScript)) {
      printWarning('Voice server start.ps1 script not found');
      return false;
    }
  } else {
    const startScript = join(VOICE_SERVER_DIR, 'start.sh');
    if (!existsSync(startScript)) {
      printWarning('Voice server start.sh script not found');
      return false;
    }
  }

  killVoiceServers();

  try {
    let command: string;
    let args: string[];

    if (IS_WINDOWS) {
      command = 'powershell';
      args = ['-ExecutionPolicy', 'Bypass', '-File', join(VOICE_SERVER_DIR, 'start.ps1')];
    } else {
      command = 'bash';
      args = [join(VOICE_SERVER_DIR, 'start.sh')];
    }

    const child = spawn(command, args, {
      detached: true,
      stdio: 'ignore',
      cwd: VOICE_SERVER_DIR,
      shell: true
    });
    child.unref();

    await new Promise(resolve => setTimeout(resolve, 2000));

    if (findRunningVoiceServers().length > 0) {
      printSuccess('Voice server started');
      return true;
    } else {
      printWarning('Voice server may not have started');
      return false;
    }
  } catch (err: any) {
    printError(`Failed to start voice server: ${err.message}`);
    return false;
  }
}

async function testVoice(message: string): Promise<boolean> {
  try {
    const response = await fetch(`http://localhost:${VOICE_SERVER_PORT}/notify`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message }),
    });
    return response.ok;
  } catch (e) {
    return false;
  }
}

// ============================================================================
// CROSS-PLATFORM BUN INSTALLATION
// ============================================================================

function installBun(): void {
  print('');
  print(`${c.bold}Checking Bun Runtime${c.reset}`);
  print(`${c.gray}─────────────────────────────────────────────────${c.reset}`);

  try {
    // Check if bun is installed
    const bunVersion = execSync('bun --version', { encoding: 'utf-8', stdio: 'pipe' }).trim();
    printSuccess(`Bun ${bunVersion} found`);

    // Upgrade to latest
    printInfo('Upgrading Bun to latest version...');
    try {
      execSync('bun upgrade', { stdio: 'inherit' });
      const newVersion = execSync('bun --version', { encoding: 'utf-8' }).trim();
      printSuccess(`Bun upgraded to ${newVersion}`);
    } catch {
      printWarning('Could not upgrade Bun (may already be latest)');
    }
  } catch {
    // Bun not installed, install it
    printInfo('Bun not found, installing...');
    try {
      if (IS_WINDOWS) {
        // Windows: Use PowerShell installer
        execSync('powershell -c "irm bun.sh/install.ps1 | iex"', {
          stdio: 'inherit',
          shell: 'powershell.exe'
        });
      } else {
        // Unix: Use curl with bash
        const result = execSync('curl -fsSL https://bun.sh/install', {
          stdio: 'pipe',
          encoding: 'utf-8'
        });

        const installScript = spawn('bash', ['-'], {
          input: result,
          stdio: 'inherit'
        });

        await new Promise<void>((resolve, reject) => {
          installScript.on('close', (code) => {
            if (code === 0) resolve();
            else reject(new Error(`Bun install failed with code ${code}`));
          });
        });
      }

      // Add bun to PATH for current session
      const bunPath = IS_WINDOWS
        ? join(HOME, '.bun', 'bin')
        : join(HOME, '.bun', 'bin');
      process.env.PATH = `${bunPath}${IS_WINDOWS ? ';' : ':'}${process.env.PATH}`;

      const newVersion = execSync('bun --version', { encoding: 'utf-8' }).trim();
      printSuccess(`Bun ${newVersion} installed`);
      printInfo('You may need to restart your terminal for bun to be in PATH');
    } catch (err: any) {
      printError(`Failed to install Bun: ${err.message}`);
      if (IS_WINDOWS) {
        printInfo('Please install manually: powershell -c "irm bun.sh/install.ps1 | iex"');
      } else {
        printInfo('Please install manually: curl -fsSL https://bun.sh/install | bash');
      }
    }
  }
}

// ============================================================================
// CROSS-PLATFORM SHELL CONFIGURATION
// ============================================================================

function setupShellAlias(): void {
  const aliasLine = IS_WINDOWS
    ? `function pai { bun $env:USERPROFILE\.claude\skills\PAI\Tools\pai.ts $args }`
    : `alias pai='bun ~/.claude/skills/PAI/Tools/pai.ts'`;

  const marker = '# PAI alias';

  try {
    if (IS_WINDOWS) {
      // PowerShell profile
      const psProfilePath = join(HOME, 'Documents', 'PowerShell', 'Microsoft.PowerShell_profile.ps1');
      let content = existsSync(psProfilePath) ? readFileSync(psProfilePath, 'utf-8') : '';

      if (content.includes('function pai')) {
        // Update existing
        content = content.replace(/function pai \{[^}]*\}/s, aliasLine);
        writeFileSync(psProfilePath, content);
        printSuccess('Updated PAI alias in PowerShell profile');
      } else {
        // Add new
        content = content.trim() + `\n${marker}\n${aliasLine}\n`;
        writeFileSync(psProfilePath, content);
        printSuccess('Added PAI alias to PowerShell profile');
      }
      printInfo('Restart PowerShell to use "pai" command');
    } else {
      // Unix shell: .zshrc or .bashrc
      const zshrcPath = join(HOME, '.zshrc');
      const bashrcPath = join(HOME, '.bashrc');

      let targetFile = existsSync(zshrcPath) ? zshrcPath : bashrcPath;
      if (!existsSync(targetFile)) {
        // Create .zshrc as default
        targetFile = zshrcPath;
      }

      let content = readFileSync(targetFile, 'utf-8');

      if (content.includes('alias pai=')) {
        // Update existing
        content = content.replace(/alias pai=.*/, aliasLine);
        writeFileSync(targetFile, content);
        printSuccess(`Updated PAI alias in ${targetFile.split(sep).pop()}`);
      } else {
        // Add new
        writeFileSync(targetFile, content + `\n${marker}\n${aliasLine}\n`);
        printSuccess(`Added PAI alias to ${targetFile.split(sep).pop()}`);
      }

      const shellName = targetFile.includes('zsh') ? 'zsh' : 'bash';
      printInfo(`Run "source ~/.${shellName}rc" to enable "pai" command`);
    }
  } catch (err: any) {
    printWarning(`Could not update shell profile: ${err.message}`);
  }
}

function reloadShell(): void {
  print('');
  print(`${c.yellow}⚠️  Please restart your terminal/shell for changes to take effect.${c.reset}`);

  if (IS_WINDOWS) {
    print(`   ${c.gray}Close and reopen PowerShell or Command Prompt${c.reset}`);
  } else if (IS_MAC) {
    print(`   ${c.gray}Run: source ~/.zshrc${c.reset}`);
  } else if (IS_LINUX) {
    print(`   ${c.gray}Run: source ~/.bashrc or source ~/.zshrc${c.reset}`);
  }
}

// ============================================================================
// SETTINGS.JSON GENERATION
// ============================================================================

function generateSettingsJson(config: InstallConfig): object {
  const AI_NAME = config.AI_NAME || 'PAI';
  const VOICE_ID = config.CUSTOM_VOICE_ID || DEFAULT_VOICES[config.VOICE_TYPE || 'male'];
  const CATCHPHRASE = config.CATCHPHRASE || `${AI_NAME} here, ready to go.`;

  return {
    "$schema": "https://json.schemastore.org/claude-code-settings.json",
    "paiVersion": "2.5",
    "env": {
      "PAI_DIR": CLAUDE_DIR,
      "PROJECTS_DIR": config.PROJECTS_DIR || "",
      "CLAUDE_CODE_MAX_OUTPUT_TOKENS": "80000",
      "BASH_DEFAULT_TIMEOUT_MS": "600000"
    },
    "contextFiles": [
      "skills/PAI/SKILL.md",
      "skills/PAI/SYSTEM/AISTEERINGRULES.md",
      "skills/PAI/USER/AISTEERINGRULES.md",
      "skills/PAI/USER/DAIDENTITY.md"
    ],
    "daidentity": {
      "name": AI_NAME,
      "fullName": `${AI_NAME} - Personal AI`,
      "displayName": AI_NAME,
      "color": "#3B82F6",
      "voiceId": VOICE_ID,
      "voice": {
        "stability": 0.35,
        "similarity_boost": 0.80,
        "style": 0.90,
        "speed": 1.1,
        "use_speaker_boost": true,
        "volume": 0.8
      },
      "startupCatchphrase": CATCHPHRASE
    },
    "principal": {
      "name": config.PRINCIPAL_NAME,
      "timezone": config.TIMEZONE || Intl.DateTimeFormat().resolvedOptions().timeZone
    },
    "pai": {
      "repoUrl": "github.com/danielmiessler/PAI",
      "version": "2.5"
    },
    "techStack": {
      "browser": "arc",
      "terminal": IS_WINDOWS ? "windows-terminal" : "kitty",
      "packageManager": "bun",
      "pythonPackageManager": "pip",
      "language": "TypeScript",
      "devServerPort": 5173
    },
    "permissions": {
      "allow": [
        "Bash", "Read", "Write", "Edit", "MultiEdit", "Glob", "Grep", "LS",
        "WebFetch", "WebSearch", "NotebookRead", "NotebookEdit", "TodoWrite",
        "ExitPlanMode", "Task", "Skill", "mcp__*"
      ],
      "deny": [],
      "ask": [
        "Bash(rm -rf /)", "Bash(rm -rf /:*)", "Bash(sudo rm -rf /)", "Bash(sudo rm -rf /:*)",
        "Bash(rm -rf ~)", "Bash(rm -rf ~:*)", "Bash(rm -rf ~/.claude)", "Bash(rm -rf ~/.claude:*)",
        "Bash(diskutil eraseDisk:*)", "Bash(diskutil zeroDisk:*)", "Bash(diskutil partitionDisk:*)",
        "Bash(diskutil apfs deleteContainer:*)", "Bash(diskutil apfs eraseVolume:*)",
        "Bash(dd if=/dev/zero:*)", "Bash(mkfs:*)", "Bash(gh repo delete:*)",
        "Bash(gh repo edit --visibility public:*)", "Bash(git push --force:*)",
        "Bash(git push -f:*)", "Bash(git push origin --force:*)", "Bash(git push origin -f:*)",
        "Read(~/.ssh/id_*)", "Read(~/.ssh/*.pem)", "Read(~/.aws/credentials)",
        "Read(~/.gnupg/private*)", "Write(~/.claude/settings.json)",
        "Edit(~/.claude/settings.json)", "Write(~/.ssh/*)", "Edit(~/.ssh/*)"
      ],
      "defaultMode": "default"
    },
    "enableAllProjectMcpServers": true,
    "enabledMcpjsonServers": [],
    "hooks": {
      "PreToolUse": [
        { "matcher": "Bash", "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/SecurityValidator.hook.ts" }] },
        { "matcher": "Edit", "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/SecurityValidator.hook.ts" }] },
        { "matcher": "Write", "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/SecurityValidator.hook.ts" }] },
        { "matcher": "Read", "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/SecurityValidator.hook.ts" }] },
        { "matcher": "AskUserQuestion", "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/SetQuestionTab.hook.ts" }] }
      ],
      "PostToolUse": [
        { "matcher": "AskUserQuestion", "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/QuestionAnswered.hook.ts" }] }
      ],
      "SessionEnd": [
        { "hooks": [
          { "type": "command", "command": "${PAI_DIR}/hooks/WorkCompletionLearning.hook.ts" },
          { "type": "command", "command": "${PAI_DIR}/hooks/SessionSummary.hook.ts" }
        ]}
      ],
      "UserPromptSubmit": [
        { "hooks": [
          { "type": "command", "command": "${PAI_DIR}/hooks/FormatReminder.hook.ts" },
          { "type": "command", "command": "${PAI_DIR}/hooks/AutoWorkCreation.hook.ts" },
          { "type": "command", "command": "${PAI_DIR}/hooks/ExplicitRatingCapture.hook.ts" },
          { "type": "command", "command": "${PAI_DIR}/hooks/ImplicitSentimentCapture.hook.ts" },
          { "type": "command", "command": "${PAI_DIR}/hooks/UpdateTabTitle.hook.ts" }
        ]}
      ],
      "SessionStart": [
        { "hooks": [
          { "type": "command", "command": "${PAI_DIR}/hooks/StartupGreeting.hook.ts" },
          { "type": "command", "command": "${PAI_DIR}/hooks/LoadContext.hook.ts" },
          { "type": "command", "command": "${PAI_DIR}/hooks/CheckVersion.hook.ts" }
        ]}
      ],
      "Stop": [{ "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/StopOrchestrator.hook.ts" }] }],
      "SubagentStop": [{ "hooks": [{ "type": "command", "command": "${PAI_DIR}/hooks/AgentOutputCapture.hook.ts" }] }]
    },
    "statusLine": {
      "type": "command",
      "command": IS_WINDOWS
        ? "${PAI_DIR}/statusline-command.ps1"
        : "${PAI_DIR}/statusline-command.sh"
    },
    "alwaysThinkingEnabled": true,
    "platform": PLATFORM,
    "installDate": new Date().toISOString(),
    "_docs": {
      "_overview": "PAI v2.5 settings. Run install wizard to customize.",
      "_sections": {
        "contextFiles": "Files loaded at session start. Defaults load SKILL.md, AI Steering Rules, and DA Identity.",
        "daidentity": "AI identity (name, voice)",
        "principal": "Your identity",
        "permissions": "Tool permissions",
        "hooks": "Lifecycle event hooks"
      }
    },
    "max_tokens": 4096
  };
}

// ============================================================================
// VALIDATION
// ============================================================================

function validate(): { passed: boolean; results: string[] } {
  const results: string[] = [];
  let passed = true;

  // Check settings.json
  const settingsPath = join(CLAUDE_DIR, 'settings.json');
  if (existsSync(settingsPath)) {
    try {
      const settings = JSON.parse(readFileSync(settingsPath, 'utf-8'));
      if (settings.principal?.name && settings.daidentity?.name) {
        results.push(`${c.green}✓${c.reset} settings.json valid`);
      } else {
        results.push(`${c.red}✗${c.reset} settings.json missing required fields`);
        passed = false;
      }
    } catch (e) {
      results.push(`${c.red}✗${c.reset} settings.json invalid JSON`);
      passed = false;
    }
  } else {
    results.push(`${c.red}✗${c.reset} settings.json not found`);
    passed = false;
  }

  // Check directories
