# VoiceServer Windows Shutdown Script
# PAI v2.5 - Cross-Platform Voice Notification Server

$ErrorActionPreference = "Stop"

$VoiceDir = "$env:USERPROFILE\.claude\VoiceServer"
$PidFile = "$VoiceDir\voice.pid"

if (-not (Test-Path $PidFile)) {
    Write-Host "VoiceServer is not running (no PID file found)" -ForegroundColor Yellow
    exit 0
}

try {
    $pid = Get-Content $PidFile -ErrorAction Stop
    $process = Get-Process -Id $pid -ErrorAction SilentlyContinue

    if ($process) {
        Write-Host "Stopping VoiceServer (PID: $pid)..." -ForegroundColor Yellow

        # Try graceful shutdown first
        $process.CloseMainWindow() | Out-Null
        Start-Sleep -Seconds 1

        if (-not $process.HasExited) {
            # Force kill if graceful shutdown failed
            $process.Kill()
            Start-Sleep -Milliseconds 500
        }

        if ($process.HasExited) {
            Remove-Item $PidFile -Force
            Write-Host "VoiceServer stopped successfully" -ForegroundColor Green
        } else {
            Write-Host "Warning: VoiceServer may still be running" -ForegroundColor Yellow
        }
    } else {
        Write-Host "VoiceServer process not found (stale PID file)" -ForegroundColor Yellow
        Remove-Item $PidFile -Force
    }
} catch {
    Write-Host "Error stopping VoiceServer: $_" -ForegroundColor Red
    Remove-Item $PidFile -Force -ErrorAction SilentlyContinue
    exit 1
}

# PAI v2.5 Status Line - PowerShell Version
# Equivalent to statusline-command.sh for Windows
#
# Usage: This script reads JSON from stdin and displays system status
# It's designed to be called by Claude Code hooks

param(
    [string]$Mode = "normal",
    [switch]$Debug
)

$ErrorActionPreference = "SilentlyContinue"

# ============================================================================
# CONFIGURATION
# ============================================================================

$PAI_DIR = if ($env:USERPROFILE) { "$env:USERPROFILE\.claude" } else { "$env:HOME\.claude" }
$SETTINGS_FILE = "$PAI_DIR\settings.json"

# ============================================================================
# COLOR FUNCTIONS
# ============================================================================

function Get-Color {
    param([string]$Name)

    $colors = @{
        reset = "`e[0m"
        bold = "`e[1m"
        cyan = "`e[38;2;6;182;212m"
        green = "`e[38;2;34;197;94m"
        yellow = "`e[38;2;234;179;8m"
        red = "`e[38;2;239;68;68m"
        blue = "`e[38;2;59;130;246m"
        gray = "`e[38;2;100;116;139m"
    }

    return $colors[$Name]
}

# ============================================================================
# GIT STATUS
# ============================================================================

function Get-GitStatus {
    $gitDir = git rev-parse --git-dir 2>$null
    if (-not $gitDir) {
        return ""
    }

    $branch = git rev-parse --abbrev-ref HEAD 2>$null
    if (-not $branch) {
        return ""
    }

    $status = git status --porcelain 2>$null
    $hasChanges = $status -and $status.Length -gt 0

    $symbol = if ($hasChanges) { "*" } else { "" }
    return "$branch$symbol"
}

# ============================================================================
# CURRENT DIRECTORY
# ============================================================================

function Get-CurrentDirectory {
    $path = (Get-Location).Path
    $home = $env:USERPROFILE

    if ($path.StartsWith($home)) {
        $path = $path.Replace($home, "~")
    }

    # Limit length
    if ($path.Length -gt 40) {
        $parts = $path.Split('\')
        $path = "$($parts[0])\...\$($parts[-1])"
    }

    return $path
}

# ============================================================================
# PAI INFO
# ============================================================================

function Get-PaiInfo {
    if (Test-Path $SETTINGS_FILE) {
        try {
            $settings = Get-Content $SETTINGS_FILE | ConvertFrom-Json
            return $settings.daidentity.name
        } catch {
            return "PAI"
        }
    }

    return "PAI"
}

# ============================================================================
# DATE/TIME
# ============================================================================

function Get-DateTime {
    return Get-Date -Format "HH:mm:ss"
}

# ============================================================================
# WINDOW SIZE
# ============================================================================

function Get-WindowSize {
    try {
        $ui = $Host.UI.RawUI
        return $ui.WindowSize.Width
    } catch {
        return 80
    }
}

# ============================================================================
# STATUS LINE DISPLAY
# ============================================================================

function Show-StatusLine {
    $width = Get-WindowSize
    $leftPad = 1
    $rightPad = 1

    # Get data
    $paiInfo = Get-PaiInfo
    $gitStatus = Get-GitStatus
    $currentDir = Get-CurrentDirectory
    $dateTime = Get-DateTime

    # Build left side
    $leftParts = @($paiInfo, $gitStatus, $currentDir)
    $leftText = $leftParts -join " | "

    # Build right side
    $rightText = $dateTime

    # Combine with padding
    $totalText = "$leftText | $rightText"

    # Apply colors
    $c = @{
        cyan = Get-Color "cyan"
        reset = Get-Color "reset"
    }

    $coloredLine = "$($c.cyan)$totalText$($c.reset)"

    # Write status line
    Write-Host "`r$coloredLine" -NoNewline
}

# ============================================================================
# MAIN LOOP
# ============================================================================

try {
    # Read JSON input from stdin (if available)
    $inputJson = ""
    if ($input.MoveNext) {
        $inputLines = @($input)
        if ($inputLines.Count -gt 0) {
            $inputJson = $inputLines -join ""
        }
    }

    # Parse JSON if available
    if ($inputJson) {
        try {
            $data = $inputJson | ConvertFrom-Json

            # Extract relevant info
            if ($data.workspace.current_dir) {
                Set-Location $data.workspace.current_dir
            }

            # Show status
            Show-StatusLine
        } catch {
            # Fallback to simple display
            Show-StatusLine
        }
    } else {
        # No JSON input, just show current status once
        Show-StatusLine
        Write-Host ""
    }

} catch {
    Write-Host "Status line error: $_" -ForegroundColor Red
}

/**
 * Cross-Platform Utilities for PAI v2.5
 *
 * Provides platform detection and platform-specific helpers
 * for Windows, macOS, and Linux.
 */

import * as os from 'os';
import * as path from 'path';

// ============================================================================
// PLATFORM DETECTION
// ============================================================================

export const PLATFORM = process.platform;
export const IS_WINDOWS = PLATFORM === 'win32';
export const IS_MAC = PLATFORM === 'darwin';
export const IS_LINUX = PLATFORM === 'linux';

// ============================================================================
// PATHS
// ============================================================================

export const HOME = IS_WINDOWS
  ? process.env.USERPROFILE || os.homedir()
  : process.env.HOME || os.homedir();

export const CLAUDE_DIR = path.join(HOME, '.claude');

export const DEFAULT_PROJECTS_DIR = path.join(HOME, 'Projects');

// ============================================================================
// PLATFORM-SPECIFIC PATHS
// ============================================================================

export function getHome(): string {
  return HOME;
}

export function getClaudeDir(): string {
  return CLAUDE_DIR;
}

export function getProjectsDir(projectsDir?: string): string {
  return projectsDir || DEFAULT_PROJECTS_DIR;
}

// ============================================================================
// COMMAND MAPPING
// ============================================================================

/**
 * Map Unix commands to Windows equivalents
 */
export function getCommand(command: string): string {
  const commandMap: Record<string, string> = {
    'ls': IS_WINDOWS ? 'dir' : 'ls',
    'cat': IS_WINDOWS ? 'type' : 'cat',
    'rm': IS_WINDOWS ? 'del' : 'rm',
    'cp': IS_WINDOWS ? 'copy' : 'cp',
    'mv': IS_WINDOWS ? 'move' : 'mv',
    'ps': IS_WINDOWS ? 'tasklist' : 'ps',
    'kill': IS_WINDOWS ? 'taskkill' : 'kill',
    'pwd': IS_WINDOWS ? 'cd' : 'pwd',
    'clear': IS_WINDOWS ? 'cls' : 'clear',
    'echo': 'echo', // Same on all platforms
    'mkdir': IS_WINDOWS ? 'mkdir' : 'mkdir', // Same but flags differ
    'rmdir': IS_WINDOWS ? 'rmdir' : 'rmdir',
  };

  return commandMap[command] || command;
}

/**
 * Get command arguments for platform
 */
export function getCommandArgs(command: string, args: string[]): string[] {
  if (IS_WINDOWS) {
    // Windows-specific argument adjustments
    if (command === 'mkdir' && !args.includes('/p')) {
      // Unix: mkdir -p → Windows: mkdir (already creates parents)
      return args.filter(arg => arg !== '-p');
    }
  }

  return args;
}

// ============================================================================
// SHELL CONFIGURATION
// ============================================================================

export interface ShellConfig {
  shell: string;
  profile: string;
  configCmd: string;
}

export function getShellConfig(): ShellConfig {
  if (IS_WINDOWS) {
    return {
      shell: 'powershell',
      profile: path.join(HOME, 'Documents', 'PowerShell', 'Microsoft.PowerShell_profile.ps1'),
      configCmd: 'pwsh',
    };
  } else if (IS_MAC) {
    return {
      shell: 'zsh',
      profile: path.join(HOME, '.zshrc'),
      configCmd: 'zsh',
    };
  } else {
    // Linux - try zsh first, fallback to bash
    const zshrc = path.join(HOME, '.zshrc');
    const hasZsh = require('fs').existsSync(zshrc);

    return {
      shell: hasZsh ? 'zsh' : 'bash',
      profile: hasZsh ? zshrc : path.join(HOME, '.bashrc'),
      configCmd: hasZsh ? 'zsh' : 'bash',
    };
  }
}

// ============================================================================
// FILE OPERATIONS
// ============================================================================

/**
 * Check if path is absolute
 */
export function isAbsolute(p: string): boolean {
  return path.isAbsolute(p);
}

/**
 * Normalize path for current platform
 */
export function normalizePath(p: string): string {
  return path.normalize(p);
}

/**
 * Join path segments
 */
export function joinPaths(...segments: string[]): string {
  return path.join(...segments);
}

// ============================================================================
// PERMISSIONS
// ============================================================================

/**
 * Set executable permission on file
 * (No-op on Windows, chmod +x on Unix)
 */
export function setExecutable(filePath: string): void {
  if (!IS_WINDOWS) {
    const { execSync } = require('child_process');
    try {
      execSync(`chmod +x "${filePath}"`, { stdio: 'pipe' });
    } catch (e) {
      // Ignore errors
    }
  }
}

/**
 * Set directory permissions
 */
export function setDirectoryPermissions(dirPath: string): void {
  if (IS_WINDOWS) {
    // Windows: Use icacls
    const { execSync } = require('child_process');
    const { userInfo } = require('os');
    const username = userInfo().username;

    try {
      execSync(`icacls "${dirPath}" /grant "${username}:(OI)(CI)F" /T`, {
        stdio: 'pipe',
        shell: true,
      });
    } catch (e) {
      // Ignore errors - default permissions usually OK
    }
  } else {
    // Unix: chmod + chown
    const { execSync } = require('child_process');
    const { userInfo } = require('os');
    const info = userInfo();

    try {
      execSync(`chmod -R 755 "${dirPath}"`, { stdio: 'pipe' });
      execSync(`chown -R ${info.uid}:${info.gid} "${dirPath}"`, { stdio: 'pipe' });
    } catch (e) {
      // Ignore errors
    }
  }
}

// ============================================================================
// PROCESS MANAGEMENT
// ============================================================================

/**
 * Find process using port
 */
export function findProcessOnPort(port: number): number[] {
  const { execSync } = require('child_process');

  try {
    if (IS_WINDOWS) {
      const result = execSync(`netstat -ano | findstr :${port}`, {
        encoding: 'utf-8',
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      const pids: number[] = [];
      const lines = result.trim().split('\n');

      for (const line of lines) {
        const parts = line.trim().split(/\s+/);
        const pid = parseInt(parts[parts.length - 1]);
        if (!isNaN(pid)) {
          pids.push(pid);
        }
      }

      return [...new Set(pids)]; // Unique PIDs
    } else {
      const result = execSync(`lsof -ti:${port}`, {
        encoding: 'utf-8',
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      return result
        .trim()
        .split('\n')
        .map((s: string) => parseInt(s.trim()))
        .filter((n: number) => !isNaN(n));
    }
  } catch (e) {
    return [];
  }
}

/**
 * Kill process by PID
 */
export function killProcess(pid: number): boolean {
  const { execSync } = require('child_process');

  try {
    if (IS_WINDOWS) {
      execSync(`taskkill /F /PID ${pid}`, { stdio: 'pipe' });
    } else {
      execSync(`kill -9 ${pid}`, { stdio: 'pipe' });
    }
    return true;
  } catch (e) {
    return false;
  }
}

// ============================================================================
// AUDIO PLAYBACK
// ============================================================================

export interface AudioConfig {
  platform: string;
  player: string;
  volumeScale: number;
}

export function getAudioConfig(): AudioConfig {
  if (IS_WINDOWS) {
    return {
      platform: 'windows',
      player: 'powershell',
      volumeScale: 1.0, // 0.0 to 1.0
    };
  } else if (IS_MAC) {
    return {
      platform: 'macos',
      player: 'afplay',
      volumeScale: 1.0, // 0.0 to 1.0
    };
  } else {
    return {
      platform: 'linux',
      player: 'paplay', // or aplay
      volumeScale: 65536, // 0 to 65536
    };
  }
}

// ============================================================================
// LOGGING
// ============================================================================

/**
 * Get log directory for platform
 */
export function getLogDir(appName: string = 'PAI'): string {
  if (IS_WINDOWS) {
    return path.join(HOME, 'AppData', 'Local', appName, 'logs');
  } else if (IS_MAC) {
    return path.join(HOME, 'Library', 'Logs', appName);
  } else {
    // Linux
    const xdgDataHome = process.env.XDG_DATA_HOME || path.join(HOME, '.local', 'share');
    return path.join(xdgDataHome, appName, 'logs');
  }
}

// ============================================================================
// ENVIRONMENT
// ============================================================================

/**
 * Get PATH environment variable delimiter
 */
export function getPathDelimiter(): string {
  return IS_WINDOWS ? ';' : ':';
}

/**
 * Add to PATH
 */
export function addToPath(dirToAdd: string): void {
  const delimiter = getPathDelimiter();
  const pathEnv = process.env.PATH || '';

  if (!pathEnv.includes(dirToAdd)) {
    process.env.PATH = `${dirToAdd}${delimiter}${pathEnv}`;
  }
}

// ============================================================================
// TROUBLESHOOTING HELPERS
// ============================================================================

/**
 * Get platform-specific troubleshooting info
 */
export function getTroubleshootingInfo(): string {
  if (IS_WINDOWS) {
    return `
Windows Troubleshooting:
- Run PowerShell as Administrator for permission issues
- Enable Long Paths: New-ItemProperty -Path "HKLM:\\SYSTEM\\CurrentControlSet\\Control\\FileSystem" -Name "LongPathsEnabled" -Value 1 -PropertyType DWORD -Force
- Set Execution Policy: Set-ExecutionPolicy -ExecutionPolicy RemoteSigned -Scope CurrentUser
- Check PATH: echo $env:PATH
`;
  } else if (IS_MAC) {
    return `
macOS Troubleshooting:
- Install Xcode Command Line Tools: xcode-select --install
- Fix permissions: sudo chown -R $(whoami) ~/.claude
- Check shell: echo $SHELL
`;
  } else {
    return `
Linux Troubleshooting:
- Fix permissions: sudo chown -R $(whoami) ~/.claude
- Check dependencies: python3, node, git
- Install missing packages via your package manager (apt, yum, dnf, etc.)
`;
  }
}

// ============================================================================
// EXPORTS
// ============================================================================

export default {
  PLATFORM,
  IS_WINDOWS,
  IS_MAC,
  IS_LINUX,
  HOME,
  CLAUDE_DIR,
  DEFAULT_PROJECTS_DIR,
  getHome,
  getClaudeDir,
  getProjectsDir,
  getCommand,
  getCommandArgs,
  getShellConfig,
  isAbsolute,
  normalizePath,
  joinPaths,
  setExecutable,
  setDirectoryPermissions,
  findProcessOnPort,
  killProcess,
  getAudioConfig,
  getLogDir,
  getPathDelimiter,
  addToPath,
  getTroubleshootingInfo,
};

